+    /// L1 (Mean Absolute Error) loss: `mean(|pred - target|)`
+    pub fn l1_loss(
+        &mut self,
+        pred: TensorNodeId,
+        target: TensorNodeId,
+    ) -> Result<TensorNodeId, AutogradError> {
+        let diff = self.tensor_sub(pred, target)?;
+        let abs_diff = self.tensor_abs(diff)?;
+        self.tensor_mean(abs_diff)
+    }
